Here's a hash table:

```
class HashTable:
    def __init__(self, size=10):
        self.size = size
        self.table = [[] for _ in range(size)]

    def hash(self, key):
        return hash(key) % self.size

    def set(self, key, value):
        h = self.hash(key)
        for i, (k, v) in enumerate(self.table[h]):
            if k == key:
                self.table[h][i] = (key, value)
                return
        self.table[h].append((key, value))

    def get(self, key):
        h = self.hash(key)
        for k, v in self.table[h]:
            if k == key:
                return v
        return None
```

Here's a hash table:

```
class HashTable:
    def __init__(self, size=10):
        self.size = size
        self.table = [[] for _ in range(size)]

    def hash(self, key):
        return hash(key) % self.size

    def set(self, key, value):
        h = self.hash(key)
        for i, (k, v) in enumerate(self.table[h]:
            if k == key:
                self.table[h][i] = (key, value)
                return
        self.table[h].append((key, value))

    def get(self, key):
        h = self.hash(key)
        for k, v in self.table[h]:
            if k == key:
                return v
        return None
```

